# 4. Verify tables and indexes
sqlite3 kanban/server/kanban-test.db ".tables"
sqlite3 kanban/server/kanban-test.db ".indexes"

# 5. Verify schema_version tracking
sqlite3 kanban/server/kanban-test.db "SELECT * FROM schema_version;"

# 6. Run migration twice to confirm idempotency
node -e "
  import('./db/schema.js').then(m => {
    const db1 = m.initDb('./kanban-test.db');
    db1.close();
    const db2 = m.initDb('./kanban-test.db');
    const rows = db2.prepare('SELECT * FROM schema_version').all();
    console.log('Migrations applied:', rows.length, '(should be 1)');
    db2.close();
  });
"
```

Expected outcomes:
