260	import Database from 'better-sqlite3';
261	import { readFileSync, readdirSync } from 'node:fs';
262	import { fileURLToPath } from 'node:url';
263	import path from 'node:path';
264	
265	const __dirname = path.dirname(fileURLToPath(import.meta.url));
266	const MIGRATIONS_DIR = path.join(__dirname, 'migrations');
267	
268	export function initDb(dbPath) {
269	  const db = new Database(dbPath);
270	  db.pragma('journal_mode = WAL');
271	  db.pragma('foreign_keys = ON');
272	
273	  // Ensure schema_version tracking table exists
274	  db.exec(`
275	    CREATE TABLE IF NOT EXISTS schema_version (
276	      version    TEXT    PRIMARY KEY,
277	      applied_at INTEGER NOT NULL
278	    )
279	  `);
280	
281	  // Find all migration files in sorted order
282	  const files = readdirSync(MIGRATIONS_DIR)
283	    .filter(f => f.endsWith('.sql'))
284	    .sort();
285	
286	  // Get already-applied versions
287	  const applied = new Set(
288	    db.prepare('SELECT version FROM schema_version').all().map(r => r.version)
289	  );
290	
291	  // Apply each pending migration inside an atomic transaction
292	  const applyMigration = db.transaction((version, sql) => {
293	    db.exec(sql);
294	    db.prepare('INSERT INTO schema_version (version, applied_at) VALUES (?, ?)').run(version, Date.now());
295	  });
296	
297	  for (const file of files) {
298	    const version = file.replace('.sql', '');
299	    if (!applied.has(version)) {
300	      const sql = readFileSync(path.join(MIGRATIONS_DIR, file), 'utf8');
301	      applyMigration(version, sql);
302	    }
303	  }
304	
305	  return db;
306	}
307	```
