function tempDbPath() {
  const dir = mkdtempSync(path.join(os.tmpdir(), 'kanban-test-'));
  return path.join(dir, 'test.db');
}

test('001_init.sql migration file exists', () => {
  assert.ok(existsSync(INIT_SQL_PATH), '001_init.sql should exist');
